    // This is a standard problem: max length subarray with equal 0s and 1s.
    // We use prefix sums (where 1 -> 1, 0 -> -1) and a hashmap to store first occurrence of prefix sums.
    let find_max_balanced_len = |arr: &[char]| -> i64 {
        let len = arr.len();
        if len == 0 {
            return 0;
        }

        // Map: balance_value -> first_index_where_this_balance_was_achieved
        let mut balance_map: std::collections::HashMap<i32, usize> = std::collections::HashMap::new();
        balance_map.insert(0, -1); // Balance 0 is achieved before index 0

        let mut current_balance = 0;
        let mut max_l = 0;

        for i in 0..len {
            let val = if arr[i] == '1' { 1 } else { -1 };
            current_balance += val;

            if let Some(&prev_index) = balance_map.get(&current_balance) {
                // A subarray from prev_index + 1 to i has a net balance of 0
                max_l = max_l.max((i as i64) - (prev_index as i64));
            } else {
                // Store the first time we see this balance
                balance_map.insert(current_balance, i);
            }
